section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/business-process-analysis.json",
  "title": "bpa-process-record",
  "type": "object",
  "required": [
    "process_id",
    "name",
    "owner",
    "tier",
    "va_pct",
    "bn_pct",
    "nva_pct",
    "baseline_metrics",
    "diff_table",
    "framework_anchor"
  ],
  "properties": {
    "process_id": {
      "type": "string",
      "pattern": "^P-[0-9]{4}$"
    },
    "name": {
      "type": "string"
    },
    "owner": {
      "type": "string"
    },
    "tier": {
      "enum": [
        "deep",
        "narrative"
      ]
    },
    "va_pct": {
      "type": "number",
      "minimum": 0,
      "maximum": 1
    },
    "bn_pct": {
      "type": "number",
      "minimum": 0,
      "maximum": 1
    },
    "nva_pct": {
      "type": "number",
      "minimum": 0,
      "maximum": 1
    },
    "baseline_metrics": {
      "type": "object",
      "required": [
        "volume_per_year",
        "cycle_time_minutes",
        "cost_per_transaction"
      ]
    },
    "diff_table": {
      "type": "array",
      "items": {
        "type": "object",
        "required": [
          "step",
          "current_actor",
          "future_actor",
          "change_type",
          "risk",
          "dependency"
        ]
      }
    },
    "framework_anchor": {
      "type": "string",
      "description": "APQC PCF / SCOR / eTOM reference id"
    },
    "deviation_log": {
      "type": "array"
    },
    "ownership_decision": {
      "enum": [
        "acquirer",
        "target",
        "hybrid",
        "new",
        "n/a"
      ]
    }
  },
  "additionalProperties": false
}
